import{_ as t}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as n,c as a,e as s}from"./app.f6447a9f.js";const e={},l=s(`<h3 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念" aria-hidden="true">#</a> 基本概念</h3><p>Jquery是一个快速，小巧且功能丰富的JavaScript库，它使HTML文档的遍历和操作，事件的处理，动画和Ajax等操作变量变得更加简单，并提供了一个简易的API，可以跨多种浏览器工作，结合了多个功能性和可扩展性</p><p>原生JS</p><ul><li>不能添加多个入口函数（window.onload）</li><li>api名字长</li><li>代码冗余</li><li>某些属性或方法存在兼容性</li><li>容错率低，前面代码错误则无法后续执行</li></ul><p>Jquery</p><ul><li>可以写多个入口函数</li><li>api名字容易记忆</li><li>代码简洁</li><li>兼容性好</li><li>容错率高</li></ul><h4 id="jquery" tabindex="-1"><a class="header-anchor" href="#jquery" aria-hidden="true">#</a> jquery</h4><p>1.文件结构</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
	window<span class="token punctuation">.</span>jQuery <span class="token operator">=</span> window<span class="token punctuation">.</span>$ <span class="token operator">=</span>jQuery<span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>2.$</p><ul><li>自执行函数，给window对象添加一个JQuery属性和$属性</li><li>$和Jquery是等价的，是一个函数</li><li>既然是函数，那么参数不一样则效果不一样</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">//匿名函数-入口函数</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token comment">//记得加逗号</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">//字符串-选择器/创建标签</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#jquery&#39;</span><span class="token punctuation">)</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;&lt;div&gt;&lt;/div&gt;&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">//dom对象-转换成jquery对象</span>
<span class="token function">$</span><span class="token punctuation">(</span>dom对象<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="对比dom" tabindex="-1"><a class="header-anchor" href="#对比dom" aria-hidden="true">#</a> 对比DOM</h4><p>DOM对象只能调用DOM属性或方法；jQuery对象只能调用jQuery属性或方法；两者之间不互通</p><p>jquery对象是一个伪数组，是dom对象的包装集</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> div<span class="token operator">=</span>document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&quot;#div&quot;</span><span class="token punctuation">)</span>

<span class="token keyword">var</span> $div<span class="token operator">=</span><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#div&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>1、DOM对象转换为Jquery对象</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>var $div = $(div)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>2、Jquery对象转换为DOM对象</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">//1.下标方式</span>
<span class="token keyword">var</span> div <span class="token operator">=</span> $div<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span>

<span class="token comment">//2.get方法</span>
<span class="token keyword">var</span> div <span class="token operator">=</span> $div<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="入口函数" tabindex="-1"><a class="header-anchor" href="#入口函数" aria-hidden="true">#</a> 入口函数</h4><ul><li>windo.onload不能写多个，后写会覆盖之前的，jquery入口函数可以多个</li><li>执行时机不同，jQuery入口函数先执行 <ul><li>jquery入口函数等待页面DOM树加载完成</li><li>window.onload等待页面所有资源加载完毕</li></ul></li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">//以下两种写法是等价的</span>
<span class="token function">$</span><span class="token punctuation">(</span>document<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">ready</span><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="多版本共存" tabindex="-1"><a class="header-anchor" href="#多版本共存" aria-hidden="true">#</a> 多版本共存</h4><p>文件是由上到下执行的，因此后引入的jQuery文件会覆盖前面的，即$符号是属于后引入jQuery的</p><ul><li><p>版本查看</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>jQuery.fn.jquery
jQuery.prototype.jquery
$.fn.jquery
$.prototype.jquery
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>多版本共存</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>版本1 版本2
$.noConflickt() //版本2释放$控制权
版本1 $
版本2 jquery

版本1 版本2 版本3
var $3 = $.noConflict() //版本3释放$控制权
var $2 = $.noConflict() //版本2释放$控制权
版本1 $
版本2 $2
版本3 $3
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>$的持续使用</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>假设已经编写好代码了即使用的是$符号，此时引入多种版本，是否需要修改所有$?
(function ($){
  //该自执行函数中可以继续使用$
  //以编写好的代码
}($3))
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h3 id="css" tabindex="-1"><a class="header-anchor" href="#css" aria-hidden="true">#</a> CSS</h3><h4 id="文本" tabindex="-1"><a class="header-anchor" href="#文本" aria-hidden="true">#</a> 文本</h4><table><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">text()</td><td style="text-align:left;">获取文本，得到匹配元素集合中每个元素的文本内容结合，包括他们的后代</td></tr><tr><td style="text-align:left;">text(&#39; &#39;)</td><td style="text-align:left;">设置文本</td></tr><tr><td style="text-align:left;">val()</td><td style="text-align:left;">获取表单值</td></tr><tr><td style="text-align:left;">val(&#39; &#39;)</td><td style="text-align:left;">设置表单值</td></tr></tbody></table><h4 id="行内样式" tabindex="-1"><a class="header-anchor" href="#行内样式" aria-hidden="true">#</a> 行内样式</h4><p><strong>获取样式</strong></p><p>获取具体div的样式值</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#div&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">css</span><span class="token punctuation">(</span><span class="token string">&#39;background-color&#39;</span><span class="token punctuation">)</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#div&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">css</span><span class="token punctuation">(</span><span class="token string">&#39;backgroundColor&#39;</span><span class="token punctuation">)</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#div&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">css</span><span class="token punctuation">(</span><span class="token string">&#39;border&#39;</span><span class="token punctuation">)</span>

<span class="token comment">//在ie浏览器中，获取类似边框样式值，需要具体</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#div&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">css</span><span class="token punctuation">(</span><span class="token string">&#39;border-top-width&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>获取所有div样式</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;div&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">css</span><span class="token punctuation">(</span><span class="token string">&#39;width&#39;</span><span class="token punctuation">)</span>
<span class="token comment">//只会返回第一个元素的样式</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>设置样式</strong></p><p>单样式</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#div&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">css</span><span class="token punctuation">(</span><span class="token string">&#39;width&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;100px&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>多样式</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#div&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">css</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
	  <span class="token literal-property property">width</span><span class="token operator">:</span><span class="token number">100</span><span class="token punctuation">,</span>
      <span class="token literal-property property">height</span><span class="token operator">:</span><span class="token number">100</span><span class="token punctuation">,</span>
      <span class="token string-property property">&#39;border&#39;</span><span class="token operator">:</span><span class="token string">&#39;1px solid red&#39;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="class" tabindex="-1"><a class="header-anchor" href="#class" aria-hidden="true">#</a> class</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.addClass()</td><td style="text-align:left;">$(&quot;#target&quot;).addClass(&quot;class1 class2&quot;);</td><td style="text-align:left;">这个方法不会替换一个样式类名。它只是简单的添加一个样式类名到元素上</td></tr><tr><td style="text-align:left;">.removeClass</td><td style="text-align:left;">$(&quot;#target&quot;).removeClass(&quot;class1 class2&quot;);</td><td style="text-align:left;">移除类名，无参数则移除所有类名</td></tr><tr><td style="text-align:left;">.hasClass</td><td style="text-align:left;">$(&quot;#target&quot;).hasClass(&quot;class1 class2&quot;);</td><td style="text-align:left;">判断是否含有这个类，有返回true，全部满足才会返回true</td></tr><tr><td style="text-align:left;">.toggleClass</td><td style="text-align:left;">$(&quot;#target&quot;).toggleClass(&quot;class1 class2&quot;);</td><td style="text-align:left;">如果在匹配的元素集合中的每个元素上存在该样式类就会被移除；如果某个元素没有这个样式类就会加上这个样式类</td></tr></tbody></table><h4 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h4><ul><li>attr()</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">attr</span><span class="token punctuation">(</span><span class="token string">&#39;src&#39;</span><span class="token punctuation">)</span> <span class="token comment">//获取匹配的元素集合中的第一个元素的属性的值</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">attr</span><span class="token punctuation">(</span><span class="token string">&#39;src&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;xxx.png&#39;</span><span class="token punctuation">)</span>  <span class="token comment">//修改属性值</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">attr</span><span class="token punctuation">(</span><span class="token string">&#39;my&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;xxx&#39;</span><span class="token punctuation">)</span>  <span class="token comment">//修改自定义属性/不存在则添加自定义属性</span>

<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">attr</span><span class="token punctuation">(</span><span class="token punctuation">{</span>  <span class="token comment">//操作多个属性</span>
	<span class="token literal-property property">src</span><span class="token operator">:</span><span class="token string">&#39;xxx.png&#39;</span><span class="token punctuation">,</span>
	<span class="token literal-property property">my</span><span class="token operator">:</span><span class="token string">&#39;xxx&#39;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>removeAttr()</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">removeAttr</span><span class="token punctuation">(</span><span class="token string">&#39;src&#39;</span><span class="token punctuation">)</span> <span class="token comment">//移除单个属性</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">removeAttr</span><span class="token punctuation">(</span><span class="token string">&#39;src alt my&#39;</span><span class="token punctuation">)</span> <span class="token comment">//移除多个属性</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>prop() reomveProp() <ul><li>同attr、removeAttr用法一样,都能够返回boolean类型值</li><li>当对内建属性修改时使用prop()方法 如input 和 按钮 元素的 <code>disabled</code> 属性, 以及 checkbox 的 <code>checked</code> 属性</li><li>不要使用此方法来删除原生的属性（ property ），比如checked, disabled, 或者 selected。这将完全移除该属性，一旦移除，不能再次被添加到元素上。使用<code>.prop(&#39;checked&#39;,false)</code>来设置这些属性值为<code>false</code>代替</li></ul></li></ul><h4 id="宽高" tabindex="-1"><a class="header-anchor" href="#宽高" aria-hidden="true">#</a> 宽高</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.width()</td><td style="text-align:left;">$(&#39;.target&#39;).height() $(&#39;.target&#39;).height(300) $(window).width(); //页面可视区 $(document).width() //html</td><td style="text-align:left;">获取或者设置宽度，不包括padding，border ，margin ；.css(width)<code>和</code>.width()之间的区别是后者返回一个没有单位的数值（400），前者是返回带有完整单位的字符串（400px）</td></tr><tr><td style="text-align:left;">.innerWidth()</td><td style="text-align:left;">$(&#39;.target&#39;).innerWidth()</td><td style="text-align:left;">获取包括padding的宽度；<code>window</code> and <code>document</code>对象，可以使用<code>.width()</code> 代替。</td></tr><tr><td style="text-align:left;">.outerWidth()</td><td style="text-align:left;">$(&#39;.target&#39;).outerWidth() $(&#39;.target&#39;).outerWidth(true)</td><td style="text-align:left;">获取包括padding，border的宽度；获取包括padding，border，margin宽度</td></tr><tr><td style="text-align:left;">.offset()</td><td style="text-align:left;">$(&#39;.target&#39;).offset()</td><td style="text-align:left;">返回包含top，left的对象，它们的值是相对于document文档的当前位置</td></tr><tr><td style="text-align:left;">.position()</td><td style="text-align:left;">$(&#39;.target&#39;).position()</td><td style="text-align:left;">返回包含top，left的对象，它们的值是相对于定位父级的位置</td></tr><tr><td style="text-align:left;">.scrollLeft()</td><td style="text-align:left;">$(&#39;.target&#39;).scrollLeft() $(window).scrollLeft()</td><td style="text-align:left;">获取/设置当前水平滚动条的位置；获取页面被卷去的宽度</td></tr></tbody></table><h3 id="选择器" tabindex="-1"><a class="header-anchor" href="#选择器" aria-hidden="true">#</a> 选择器</h3><h4 id="基本选择器" tabindex="-1"><a class="header-anchor" href="#基本选择器" aria-hidden="true">#</a> 基本选择器</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">ID选择器</td><td style="text-align:left;">$(&#39;#id&#39;)</td><td style="text-align:left;">获取指定ID元素</td></tr><tr><td style="text-align:left;">类选择器</td><td style="text-align:left;">$(&#39;.class&#39;)</td><td style="text-align:left;">获取同一类class元素</td></tr><tr><td style="text-align:left;">标签选择器</td><td style="text-align:left;">$(&#39;div&#39;)</td><td style="text-align:left;">获取同一类标签的所有元素</td></tr><tr><td style="text-align:left;">并集选择器</td><td style="text-align:left;">$(&#39;div,p&#39;)</td><td style="text-align:left;">逗号分隔</td></tr><tr><td style="text-align:left;">交集选择器</td><td style="text-align:left;">$(&#39;div.rclass&#39;)</td><td style="text-align:left;">获取class为rclass的div元素</td></tr></tbody></table><h4 id="层级选择器" tabindex="-1"><a class="header-anchor" href="#层级选择器" aria-hidden="true">#</a> 层级选择器</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">子代选择器</td><td style="text-align:left;">$(&#39;ul&gt;li&#39;)</td><td style="text-align:left;">获取亲儿子层级</td></tr><tr><td style="text-align:left;">后代选择器</td><td style="text-align:left;">$(&#39;ul li&#39;)</td><td style="text-align:left;">获取ul下的所有li</td></tr></tbody></table><h4 id="过滤选择器" tabindex="-1"><a class="header-anchor" href="#过滤选择器" aria-hidden="true">#</a> 过滤选择器</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">:eq(index)</td><td style="text-align:left;">$(&#39;li:eq(2)&#39;)</td><td style="text-align:left;">获取li中索引号为2的元素</td></tr><tr><td style="text-align:left;">:odd</td><td style="text-align:left;">$(&#39;li:odd&#39;) $(&#39;li[odd]&#39;)</td><td style="text-align:left;">获取li中索引号为奇数的元素</td></tr><tr><td style="text-align:left;">:even</td><td style="text-align:left;">$(&#39;li:even&#39;) $(&#39;li[even]&#39;)</td><td style="text-align:left;">获取li中索引号为偶数的元素</td></tr><tr><td style="text-align:left;">:selected</td><td style="text-align:left;">$(&#39;option:selected&#39;)</td><td style="text-align:left;">获取option中被选中状态的元素</td></tr><tr><td style="text-align:left;">:radio</td><td style="text-align:left;">$(&#39;input:radio&#39;)</td><td style="text-align:left;">选择所有类型为单选框的元素</td></tr><tr><td style="text-align:left;">:lt()</td><td style="text-align:left;">$(&quot;td:lt(index)&quot;)</td><td style="text-align:left;">选择匹配集合中所有索引值小于给定*<code>index</code>*参数的元素。</td></tr><tr><td style="text-align:left;">:gt()</td><td style="text-align:left;">$(&quot;td:gt(index)&quot;)</td><td style="text-align:left;">选择匹配集合中所有大于给定*<code>index</code>*（索引值）的元素。</td></tr><tr><td style="text-align:left;">:disabled</td><td style="text-align:left;">$(&quot;input:disabled&quot;)</td><td style="text-align:left;">选择所有被禁用的元素。</td></tr><tr><td style="text-align:left;">:checked</td><td style="text-align:left;"></td><td style="text-align:left;">匹配所有勾选的元素；<code>:checked</code> 选择器适用于复选框和单选框。对于下拉框元素, 使用 <code>:selected</code> 选择器</td></tr><tr><td style="text-align:left;">[name^=&quot;value&quot;]【属性选择器】</td><td style="text-align:left;">$(&#39;input[name^=&quot;news&quot;]&#39;)</td><td style="text-align:left;">选择指定属性是以给定字符串开始的元素</td></tr><tr><td style="text-align:left;">:hidden</td><td style="text-align:left;">$(&quot;body&quot;).find(&quot;:hidden&quot;)</td><td style="text-align:left;">选择所有隐藏的元素</td></tr><tr><td style="text-align:left;">:visible</td><td style="text-align:left;">$(&quot;body&quot;).find(&quot;:vivsible&quot;)</td><td style="text-align:left;">选择所有可见的元素</td></tr></tbody></table><h4 id="筛选选择器" tabindex="-1"><a class="header-anchor" href="#筛选选择器" aria-hidden="true">#</a> 筛选选择器</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.eq(index)</td><td style="text-align:left;">$(&#39;li).eq(2)</td><td style="text-align:left;">相当于$(&#39;li:eq(2)&#39;)</td></tr><tr><td style="text-align:left;">.slice(index,end)。</td><td style="text-align:left;">$(&#39;ul li&#39;).slice(1,3)</td><td style="text-align:left;">选取第2-3个元素</td></tr><tr><td style="text-align:left;">.filter(&#39; &#39;)</td><td style="text-align:left;">$(&quot;ul li&quot;).filter(&quot;:even&quot;);</td><td style="text-align:left;">选取ul li中所有奇数顺序的元素</td></tr><tr><td style="text-align:left;">.contents()</td><td style="text-align:left;">$(&quot;#test&quot;).contents()</td><td style="text-align:left;">返回#test里面的所有内容，包括节点和文本</td></tr><tr><td style="text-align:left;">.find(selector)</td><td style="text-align:left;">$(&#39;ul&#39;).find(&#39;li&#39;)</td><td style="text-align:left;">相当于后代选择器</td></tr><tr><td style="text-align:left;">.parent()</td><td style="text-align:left;">$(&#39;#first&#39;).parent() $(&#39;#first&#39;).parents()</td><td style="text-align:left;">查找父元素；全部父节点（包括祖先）</td></tr><tr><td style="text-align:left;">.children(selector)</td><td style="text-align:left;">$(&#39;ul&#39;).children(&#39;li&#39;) $(&#39;ul&#39;).children()</td><td style="text-align:left;">相当于子代选择器；全部子节点</td></tr><tr><td style="text-align:left;">.next()</td><td style="text-align:left;">$(&#39;li&#39;).next()</td><td style="text-align:left;">查找下一个兄弟节点</td></tr><tr><td style="text-align:left;">.prev()</td><td style="text-align:left;">$(&#39;li&#39;).prev()</td><td style="text-align:left;">查找上一个兄弟节点</td></tr><tr><td style="text-align:left;">.prevAll()</td><td style="text-align:left;">$(&#39;li&#39;).prevAll()</td><td style="text-align:left;">查找之前的所有兄弟</td></tr><tr><td style="text-align:left;">.nextAll()</td><td style="text-align:left;">$(&#39;li&#39;).nextAll()</td><td style="text-align:left;">查找之后的所有兄弟</td></tr><tr><td style="text-align:left;">.siblings(selector)</td><td style="text-align:left;">$(&#39;#first&#39;).siblings(&#39;li&#39;)</td><td style="text-align:left;">查找兄弟节点，不包括自身</td></tr></tbody></table><h4 id="遍历" tabindex="-1"><a class="header-anchor" href="#遍历" aria-hidden="true">#</a> 遍历</h4><p>jQuery中默认存在隐式迭代，会自动便利jQuery对象集合</p><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.each(function(idx,el))</td><td style="text-align:left;">遍历一个jQuery对象，为每个匹配元素执行一个函数。</td></tr><tr><td style="text-align:left;">.end()</td><td style="text-align:left;">终止在当前链的最新过滤操作，并返回匹配的元素的以前状态</td></tr><tr><td style="text-align:left;">.has()</td><td style="text-align:left;">筛选匹配元素集合中的那些有相匹配的选择器或DOM元素的后代元素</td></tr><tr><td style="text-align:left;">.is()</td><td style="text-align:left;">判断当前匹配的元素集合中的元素，是否为一个选择器，DOM元素，或者jQuery对象，如果这些元素至少一个匹配给定的参数，那么返回*<code>true</code></td></tr><tr><td style="text-align:left;">.not()</td><td style="text-align:left;">从匹配的元素集合中移除指定的元素</td></tr><tr><td style="text-align:left;">.offsetParent()</td><td style="text-align:left;">取得离指定元素最近的含有定位信息的祖先元素。含有定位信息的元素指的是，CSS 的 position 属性是 relative, absolute, 或 fixed 的元素。</td></tr></tbody></table><h3 id="事件" tabindex="-1"><a class="header-anchor" href="#事件" aria-hidden="true">#</a> 事件</h3><h4 id="鼠标事件" tabindex="-1"><a class="header-anchor" href="#鼠标事件" aria-hidden="true">#</a> 鼠标事件</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.click()</td><td style="text-align:left;">$(&quot;#target&quot;).click()</td><td style="text-align:left;">一个元素被点击和鼠标按键被按下和释放时候将触发 <code>click</code> 事件</td></tr><tr><td style="text-align:left;">.contextmenu()</td><td style="text-align:left;">$( &quot;#target&quot; ).contextmenu()</td><td style="text-align:left;">鼠标右键触发</td></tr><tr><td style="text-align:left;">.dblclick()</td><td style="text-align:left;">$(&#39;#target&#39;).dblclick()</td><td style="text-align:left;">一个元素被双击时将触发 <code>dblclick</code> 事件</td></tr><tr><td style="text-align:left;">.hover()</td><td style="text-align:left;">$(&#39;&#39;#target&#39;).hover</td><td style="text-align:left;">简写$(selector).mouseenter(handlerIn).mouseleave(handlerOut);</td></tr><tr><td style="text-align:left;">.mousedown()</td><td style="text-align:left;">$(&#39;#target&#39;).mousedown()</td><td style="text-align:left;">鼠标按下，如果在一个元素按住了鼠标不放，并且拖动鼠标离开这个元素，并释放鼠标键，这仍然是算作<code>mousedown</code>事件</td></tr><tr><td style="text-align:left;">.mouseup()</td><td style="text-align:left;">$(&#39;#target&#39;).mouseup()</td><td style="text-align:left;">当鼠标指针在元素内，并且鼠标按键被释放时，<code>mouseup</code>事件就会被触发</td></tr><tr><td style="text-align:left;">.mouseenter()</td><td style="text-align:left;">$(&#39;&#39;#target&#39;).mouseenter()</td><td style="text-align:left;">该事件在鼠标移入到元素上时被触发</td></tr><tr><td style="text-align:left;">.mouseleave()</td><td style="text-align:left;">$(&#39;&#39;#target&#39;).mouseleave()</td><td style="text-align:left;">该事件在鼠标离开元素上时被触发</td></tr><tr><td style="text-align:left;">.mousemove()</td><td style="text-align:left;">$(&quot;#target&quot;).mousemove()</td><td style="text-align:left;">当鼠标指针在元素内移动时，mousemove事件就会被触发</td></tr><tr><td style="text-align:left;">.mouseout()</td><td style="text-align:left;">$(&#39;#target&#39;).mouseout()</td><td style="text-align:left;">当鼠标指针离开元素时，mouseout事件就会被触发;<em>当鼠标移出绑定 mouseout 事件元素的子元素时，mouseout 事件同样会被触发。但是，只有在绑定 mouseleave 事件的元素上，将鼠标移出时，才会触发该事件。</em></td></tr><tr><td style="text-align:left;">.mouseover()</td><td style="text-align:left;">$(&#39;&#39;#target&#39;).mouseover</td><td style="text-align:left;">当鼠标指针进入元素内时，mouseover事件就会被触发;<em>当鼠标移入绑定 mouseover 事件元素的子元素时，mouseover 事件同样会被触发。但是，只有在绑定 mouseenter 事件的元素上，将鼠标移入时，才会触发该事件。</em></td></tr></tbody></table><h4 id="键盘事件" tabindex="-1"><a class="header-anchor" href="#键盘事件" aria-hidden="true">#</a> 键盘事件</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.keydown()</td><td style="text-align:left;">$(&#39;#target&#39;).keydown()</td><td style="text-align:left;">当用户在一个元素上第一次按下键盘上的键的时候，<code>keydown</code>事件就会发送给这个元素。它可以绑定到任何元素，但该事件只是发送到具有焦点的元素上</td></tr><tr><td style="text-align:left;">.keyup()</td><td style="text-align:left;">$(&#39;#target&#39;).keyup()</td><td style="text-align:left;">当用户在一个元素上释放按键的时候，<code>keyup</code>事件就会被附加到这个元素。它可以绑定到任何元素，但该事件只是发送到获取焦点的元素上</td></tr><tr><td style="text-align:left;">.keypress()</td><td style="text-align:left;">$(&#39;#target&#39;).keypress()</td><td style="text-align:left;">当浏览器捕获一个元素上键盘输入时，<code>keypress</code>就会发送个元素。这是类似<code>keydown</code>事件，除了当按键被一直按下（即连续插入字符的场合）时的处理。如果用户按下并按住这个键（不松开释放）的时候，<code>keydown</code>事件只触发一次，但是<code>keypress</code>会在每个字符插入的时候都会触发事件。此外，组合键（如Shift）会触发<code>keydown</code>事件，但不会触发<code>keypress</code>事件</td></tr></tbody></table><h4 id="表单事件" tabindex="-1"><a class="header-anchor" href="#表单事件" aria-hidden="true">#</a> 表单事件</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.blur()</td><td style="text-align:left;">一个元素失去焦点将触发<code>blur</code>事件。起初，这个事件仅适用于表单元素，如元素<code>&lt;input&gt;</code> 。在最新的浏览器中，这个事件适用范围已经扩大到包括所有元素类型。一个元素可以通过键盘命令失去焦点，比如tab键，或用鼠标点击网页上的其他地方。【不支持冒泡】</td></tr><tr><td style="text-align:left;">.change()</td><td style="text-align:left;">一个元素的值改变的时候将触发<code>change</code>事件。此事件仅限用于<code>&lt;input&gt;</code>元素，<code>&lt;textarea&gt;</code>和<code>&lt;select&gt;</code>元素。对于下拉选择框，复选框和单选按钮，当用户用鼠标作出选择，该事件立即触发，但对于其他类型的input元素，该事件触发将推迟，直到元素失去焦点才会触点</td></tr><tr><td style="text-align:left;">.focus()</td><td style="text-align:left;">当一个元素获得焦点时，<code>focus</code>事件被触发。此事件起初适用于有限的元素，比如表单元素（<code>&lt;input&gt;</code>, <code>&lt;select&gt;</code>等）和链接元素（<code>&lt;a href&gt;</code>）。在最近版本的浏览器中，该事件可以扩展到所有包括通过显式设置<code>tabindex</code>属性的元素类型。一个元素可以通过键盘命令获得焦点，如Tab键，或按鼠标点击的元素。</td></tr><tr><td style="text-align:left;">.focusin()</td><td style="text-align:left;"><code>focusin</code> 事件会在元素（或者其内部的任何元素）获得焦点时触发。这跟 [focus] 事件的显著区别在于，它可以在父元素上检测子元素获得焦点的情况(换而言之，它支持事件冒泡)</td></tr><tr><td style="text-align:left;">.focusout()</td><td style="text-align:left;"><code>focusout</code> 事件会在元素（或者其内部的任何元素）失去焦点时触发。这跟 [blur] 事件的显著区别在于，它可以在父元素上检测子元素失去焦点的情况(换而言之，它支持事件冒泡)。</td></tr><tr><td style="text-align:left;">.select()</td><td style="text-align:left;">当用户在一个元素中进行文本选择时，这个元素上的<code>select</code>事件就会被触发。此事件只能用在<code>&lt;input type=&quot;text&quot;&gt;</code> 和<code>&lt;textarea&gt;</code>。</td></tr><tr><td style="text-align:left;">.submit()</td><td style="text-align:left;">当用户试图提交表单时，就会在这个表单元素上触发<code>submit</code>事件。它只能绑定在<code>&lt;form&gt;</code>元素上。以下几种情况会导致表单被提交：用户点击了<code>&lt;input type=&quot;submit&quot;&gt;</code>, <code>&lt;input type=&quot;image&quot;&gt;</code>, 或者 <code>&lt;button type=&quot;submit&quot;&gt;</code>，或者当某些表单元素获取焦点时，敲击Enter（回车键），都可以提交。</td></tr></tbody></table><h4 id="绑定事件" tabindex="-1"><a class="header-anchor" href="#绑定事件" aria-hidden="true">#</a> 绑定事件</h4><h5 id="弃用api" tabindex="-1"><a class="header-anchor" href="#弃用api" aria-hidden="true">#</a> 弃用API</h5><ul><li>bind 支持同时注册，不支持动态注册</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">bind</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
   <span class="token function-variable function">click</span><span class="token operator">:</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
   <span class="token function-variable function">mouseenter</span><span class="token operator">:</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>delegate 支持同时注册，支持动态注册</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>参数一：要绑定事件的元素
参数二：事件类型
参数三：处理函数

事件委托，将要绑定事件的工作交给它的父级元素，原理：事件冒泡

<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.parent&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">delegate</span><span class="token punctuation">(</span><span class="token string">&#39;p&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">,</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="on绑定" tabindex="-1"><a class="header-anchor" href="#on绑定" aria-hidden="true">#</a> on绑定</h5><ul><li>简单注册，支持同时注册，不支持动态注册</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
   <span class="token function-variable function">click</span><span class="token operator">:</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
          console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;点击事件&#39;</span><span class="token punctuation">)</span>
     <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token function-variable function">mouseenter</span><span class="token operator">:</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> 	<span class="token punctuation">{</span>
        console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;移入事件&#39;</span><span class="token punctuation">)</span>
     <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>事件委托,支持同时动态注册</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.parent&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;span,p&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">,</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h5 id="off解绑" tabindex="-1"><a class="header-anchor" href="#off解绑" aria-hidden="true">#</a> off解绑</h5><ul><li><code>$(selector).off()</code> 解绑所有事件</li><li><code>$(selector).off(&#39;click mouseenter&#39;)</code> 解绑指定事件</li></ul><h4 id="触发器" tabindex="-1"><a class="header-anchor" href="#触发器" aria-hidden="true">#</a> 触发器</h4><ul><li>代码触发，达到条件即可触发事件</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">,</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
	console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;点击事件&#39;</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token keyword">var</span> count <span class="token operator">=</span> <span class="token number">0</span> <span class="token punctuation">;</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.btn&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">,</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
	<span class="token keyword">if</span><span class="token punctuation">(</span>count <span class="token operator">++</span> <span class="token operator">==</span><span class="token number">2</span> <span class="token punctuation">)</span><span class="token punctuation">{</span>
		<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">trigger</span><span class="token punctuation">(</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">)</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>自定义事件触发</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;customize&#39;</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;自定义事件&#39;</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.btn&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;.target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">trigger</span><span class="token punctuation">(</span><span class="token string">&#39;customize&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="事件对象" tabindex="-1"><a class="header-anchor" href="#事件对象" aria-hidden="true">#</a> 事件对象</h4><p>注册事件后，系统会自动生成一个对象记录有关注册事件的信息</p><p>jQuery中用事件参数e获取，不传参数可直接使用event，但是会缺少data字段</p><table><thead><tr><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">e.screenX</td><td style="text-align:left;">触发事件那一点 距离 屏幕最左上角的值</td></tr><tr><td style="text-align:left;">e.clientX</td><td style="text-align:left;">触发事件那一点 距离 可视区最左上角的值</td></tr><tr><td style="text-align:left;">e.pageX</td><td style="text-align:left;">触发事件那一点 距离 页面左上角的值</td></tr><tr><td style="text-align:left;">e.stopPropagation()</td><td style="text-align:left;">阻止事件冒泡</td></tr><tr><td style="text-align:left;">e.isPropagationStopped()</td><td style="text-align:left;">是否调用e.stopPropagation(),返回bollean</td></tr><tr><td style="text-align:left;">e.preventDefault()</td><td style="text-align:left;">阻止默认行为，如a链接点击跳转</td></tr><tr><td style="text-align:left;">e.isDefaultPrevented()</td><td style="text-align:left;">根据事件对象中是否调用过e.preventDefault()方法,来返回一个布尔值</td></tr><tr><td style="text-align:left;">e.keyCode</td><td style="text-align:left;">获取按下键的ASII(大写)</td></tr><tr><td style="text-align:left;">e.metaKey</td><td style="text-align:left;">win键是否被按下，返回bollean</td></tr><tr><td style="text-align:left;">e.which</td><td style="text-align:left;">针对键盘和鼠标事件，这个属性能确定你到底按的是哪个键(优先)</td></tr><tr><td style="text-align:left;">e.currentTarget</td><td style="text-align:left;">在事件冒泡过程中的当前DOM元素</td></tr><tr><td style="text-align:left;">e.target</td><td style="text-align:left;">触发事件的DOM元素</td></tr><tr><td style="text-align:left;">e.data</td><td style="text-align:left;">触发事件的DOM元素的可选数据对象</td></tr><tr><td style="text-align:left;">e.delegateTarget</td><td style="text-align:left;">绑定了当前正在调用jQuery 事件处理器的元素</td></tr><tr><td style="text-align:left;">e.stopImmediatePropagation()</td><td style="text-align:left;">阻止剩余的事件处理函数执行并且防止事件冒泡到DOM树上</td></tr><tr><td style="text-align:left;">e.isImmediatePropagationStopped()</td><td style="text-align:left;">根据事件对象中是否调用过 e.stopImmediatePropagation() 方法,来返回一个布尔值</td></tr><tr><td style="text-align:left;">e.relatedTarget</td><td style="text-align:left;">在事件中涉及的其它任何DOM元素</td></tr><tr><td style="text-align:left;">et.result</td><td style="text-align:left;">事件被触发的一个事件处理程序的最后返回值，除非值是 <code>undefined</code></td></tr><tr><td style="text-align:left;">event.timeStamp</td><td style="text-align:left;">这个属性返回事件触发时距离1970年1月1日的毫秒数</td></tr><tr><td style="text-align:left;">e.type</td><td style="text-align:left;">事件类型</td></tr></tbody></table><h4 id="浏览器事件" tabindex="-1"><a class="header-anchor" href="#浏览器事件" aria-hidden="true">#</a> 浏览器事件</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.error()</td><td style="text-align:left;">$(&#39;.target&#39;).erro()</td><td style="text-align:left;">当一个脚本错误的时候，浏览器就会触发 window 的 error 事件；比如一张图片被引用，由浏览器加载。如果没有正确载入，这个事件就会被调用。（弃用）</td></tr><tr><td style="text-align:left;">.resize()</td><td style="text-align:left;">$(window).resize()</td><td style="text-align:left;">当浏览器window的尺寸改变时，<code>window</code>元素上绑定的<code>resize</code>事件将被触发</td></tr><tr><td style="text-align:left;">.scroll()</td><td style="text-align:left;">$(&#39;#target&#39;).scroll()</td><td style="text-align:left;">当用户在元素内执行了滚动操作，就会在这个元素上触发<code>scroll</code>事件</td></tr></tbody></table><h3 id="特效" tabindex="-1"><a class="header-anchor" href="#特效" aria-hidden="true">#</a> 特效</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>他们都有三个参数，可选
参数一：持续时间 字符串(normal slow fast) 数字
参数二：速度曲线 字符串(linear swing) 其他效果借用插件
参数三：动画执行完毕后执行的函数
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="基本特效" tabindex="-1"><a class="header-anchor" href="#基本特效" aria-hidden="true">#</a> 基本特效</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.hide()</td><td style="text-align:left;">$(&#39;.target&#39;).hide()</td><td style="text-align:left;">匹配的元素将被立即隐藏，没有动画。这大致相当于.css(&#39;display&#39;,&#39;none&#39;)\`</td></tr><tr><td style="text-align:left;">.show()</td><td style="text-align:left;">$(&#39;.target&#39;).show()</td><td style="text-align:left;">匹配的元素将被立即显示，没有动画</td></tr><tr><td style="text-align:left;">.toggle()</td><td style="text-align:left;">$(&#39;.target&#39;).toggle()</td><td style="text-align:left;">切换一个元素可见性</td></tr></tbody></table><h4 id="滑动" tabindex="-1"><a class="header-anchor" href="#滑动" aria-hidden="true">#</a> 滑动</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.slideDown()</td><td style="text-align:left;">$(&#39;.target&#39;).slidDown()</td><td style="text-align:left;">将给匹配元素的高度的动画，这会导致页面的下面部分滑下去，弥补了显示的方式</td></tr><tr><td style="text-align:left;">.slideUp()</td><td style="text-align:left;">$(&#39;.target&#39;).slideUp()</td><td style="text-align:left;">将给匹配元素的高度的动画，这会导致页面的下面部分滑上去，当一个隐藏动画后，高度值达到0的时候，<code>display</code> 样式属性被设置为<code>none</code>，以确保该元素不再影响页面布局</td></tr><tr><td style="text-align:left;">.slideToggle()</td><td style="text-align:left;">$(&#39;.target&#39;).slidToggle()</td><td style="text-align:left;">将给匹配元素的高度的动画，这会导致页面中，在这个元素下面的内容往下或往上滑</td></tr></tbody></table><h4 id="渐变" tabindex="-1"><a class="header-anchor" href="#渐变" aria-hidden="true">#</a> 渐变</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.fadeIn()</td><td style="text-align:left;">$(&#39;.target&#39;).fadeIn()</td><td style="text-align:left;">透明度0-1</td></tr><tr><td style="text-align:left;">.fadeOut()</td><td style="text-align:left;">$(&#39;.target&#39;).fadeOut()</td><td style="text-align:left;">透明度1-0</td></tr><tr><td style="text-align:left;">.fadeToggle()</td><td style="text-align:left;">$(&#39;.target&#39;).fadeToggle()</td><td style="text-align:left;">切换</td></tr><tr><td style="text-align:left;">.fadeTo()</td><td style="text-align:left;">$(&#39;.target&#39;).fadeTo(0.5)</td><td style="text-align:left;">可设置界限，透明度1-0.5 、0-0.5</td></tr><tr><td style="text-align:left;">.delay()</td><td style="text-align:left;">$(&#39;.target&#39;).delay()</td><td style="text-align:left;">延时</td></tr></tbody></table><h4 id="自定义动画" tabindex="-1"><a class="header-anchor" href="#自定义动画" aria-hidden="true">#</a> 自定义动画</h4><p>除了使用jquery中定义好的动画效果，我们也可以自定义动画</p><table><thead><tr><th>animate</th><th>描述</th></tr></thead><tbody><tr><td>参数1</td><td>一个CSS属性和值的对象,动画将根据这组对象移动;一个CSS属性和值的对象,动画将根据这组对象移动; 所有用于动画的属性值必须是数字的，除非另有说明；这些属性如果不是数字的将不能使用基本的jQuery功能(需要添加插件); 动画属性也可以是一个相对值。如果提供一个以+= 或 -=开始的值，那么目标值就是以这个属性的当前值加上或者减去给定的数字来计算的</td></tr><tr><td>参数2</td><td>一个字符串或者数字决定动画将运行多久</td></tr><tr><td>参数3</td><td>一个字符串，表示过渡使用哪种缓动函数</td></tr><tr><td>参数4</td><td>在动画完成时执行的函数</td></tr></tbody></table><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&quot;#right&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">click</span><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&quot;.block&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">animate</span><span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token string-property property">&quot;left&quot;</span><span class="token operator">:</span> <span class="token string">&quot;+=50px&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token string">&quot;slow&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;li&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">animate</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">opacity</span><span class="token operator">:</span> <span class="token number">.5</span><span class="token punctuation">,</span>
  <span class="token literal-property property">height</span><span class="token operator">:</span> <span class="token string">&#39;50%&#39;</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">{</span>
  <span class="token literal-property property">duration</span><span class="token operator">:</span><span class="token number">1000</span><span class="token punctuation">,</span>
  <span class="token function-variable function">step</span><span class="token operator">:</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">now<span class="token punctuation">,</span> fx</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">//now:每一步动画属性的值，fx一个原型对象</span>
    <span class="token keyword">var</span> data <span class="token operator">=</span> fx<span class="token punctuation">.</span>elem<span class="token punctuation">.</span>id <span class="token operator">+</span> <span class="token string">&#39; &#39;</span> <span class="token operator">+</span> fx<span class="token punctuation">.</span>prop <span class="token operator">+</span> <span class="token string">&#39;: &#39;</span> <span class="token operator">+</span> now<span class="token punctuation">;</span>
    <span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;body&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">append</span><span class="token punctuation">(</span><span class="token string">&#39;&lt;div&gt;&#39;</span> <span class="token operator">+</span> data <span class="token operator">+</span> <span class="token string">&#39;&lt;/div&gt;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function-variable function">complete</span><span class="token operator">:</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="动画队列" tabindex="-1"><a class="header-anchor" href="#动画队列" aria-hidden="true">#</a> 动画队列</h4><p>Jquery动画中存在一个队列，当对象调用动画方法时，如果正在执行某个动画，则会将之后的动画存放在一个队列中，按顺序执行</p><table><thead><tr><th>stop</th><th>描述</th></tr></thead><tbody><tr><td>参数1，默认false</td><td>是否清除动画队列</td></tr><tr><td>参数2，默认false</td><td>是否立即完成当前动画</td></tr></tbody></table><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#box&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">click</span><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#target&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">slidDown</span><span class="token punctuation">(</span><span class="token number">2000</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">slildeUp</span><span class="token punctuation">(</span><span class="token number">2000</span><span class="token punctuation">)</span><span class="token comment">//动画队列</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>


<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#stop&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">stop</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token comment">//立即完成当前动画</span>

<span class="token comment">//清除所有动画，展示动画的最终结果</span>
<span class="token comment">//区别：finish会引起所有排队动画的css属性停止</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#stop&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">stop</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">,</span><span class="token boolean">true</span><span class="token punctuation">)</span>
<span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;#stop&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">finish</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="节点操作" tabindex="-1"><a class="header-anchor" href="#节点操作" aria-hidden="true">#</a> 节点操作</h3><h4 id="创建节点" tabindex="-1"><a class="header-anchor" href="#创建节点" aria-hidden="true">#</a> 创建节点</h4><p>1.html()</p><p>获取内容 <code>$(&#39;#target).html()</code> 如果选择器匹配多个元素，那么只有第一个匹配元素的 HTML 内容会被获取</p><p>设置内容 <code>$(&#39;#target&#39;).html(&#39;&lt;a href=&quot;&quot;&gt;百度&lt;/a&gt;&#39;) 能够解析标签</code></p><p>2.$()</p><p>创建元素 <code>var $link = $(&#39;&lt;a href=&quot;&quot;&gt;百度&lt;/a&gt;&#39;)</code></p><p>该方式创建的元素只存在内存中，需要添加到html页面中才能显示</p><h4 id="追加节点" tabindex="-1"><a class="header-anchor" href="#追加节点" aria-hidden="true">#</a> 追加节点</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.append()</td><td style="text-align:left;">$(&#39;.target&#39;).append(&#39;<p>Test</p>&#39;)</td><td style="text-align:left;">将参数内容插入到每个匹配元素的后面，作为子元素；如果一个被选中的元素(已存在)被插入到另外一个地方，这是移动而不是复制</td></tr><tr><td style="text-align:left;">.prepend()</td><td style="text-align:left;">$(&#39;.target&#39;).prepend(&#39;<p>Test</p>&#39;)</td><td style="text-align:left;">将参数内容插入到每个匹配元素的前面，作为子元素；存在则为移动</td></tr><tr><td style="text-align:left;">.appendTo()</td><td style="text-align:left;">$(&#39;<p>Test</p>&#39;).appendTo(&#39;.target&#39;)</td><td style="text-align:left;">将匹配元素作为子元素插入到目标元素的后面</td></tr><tr><td style="text-align:left;">.prependTo()</td><td style="text-align:left;">$(&#39;<p>Test</p>&#39;).prependTo(&#39;.target&#39;)</td><td style="text-align:left;">将匹配元素作为子元素插入到目标元素的前面</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">.before()</td><td style="text-align:left;">$(&#39;.target&#39;).before(&#39;<p>Test</p>&#39;)</td><td style="text-align:left;">在匹配元素的前面插入参数内容，作为兄弟节点</td></tr><tr><td style="text-align:left;">.after()</td><td style="text-align:left;">$(&#39;.target&#39;).after(&#39;<p>Test</p>&#39;)</td><td style="text-align:left;">在匹配元素的后面插入参数内容，作为兄弟节点</td></tr><tr><td style="text-align:left;">.insertBefore()</td><td style="text-align:left;">$(&#39;<p>Test</p>&#39;).insertBefore(&#39;.target&#39;)</td><td style="text-align:left;">将匹配元素作为兄弟元素插入到目标元素的前面面</td></tr><tr><td style="text-align:left;">.insertAfter()</td><td style="text-align:left;">$(&#39;<p>Test</p>&#39;).insertAfter(&#39;.targetr&#39;)</td><td style="text-align:left;">将匹配元素作为兄弟元素插入到目标元素的后面</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"></td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">.wrap()</td><td style="text-align:left;">$(&quot;.target&quot;).wrap(&quot;<div></div>&quot;) $(&#39;.target&#39;).wrap(function() { return &#39;<div class="&#39; + $(this).text() + &#39;"></div>&#39;; });</td><td style="text-align:left;">一个HTML片段，选择表达式，jQuery对象，或者DOM元素，用来包在匹配元素的外层</td></tr><tr><td style="text-align:left;">.unwrap()</td><td style="text-align:left;">$(&quot;.target&quot;).unwrap()</td><td style="text-align:left;">将匹配元素集合的父级元素删除，保留自身（和兄弟元素，如果存在）在原来的位置</td></tr><tr><td style="text-align:left;">.wrapAll()</td><td style="text-align:left;">$(&#39;.target).wrapAll(&#39;<div class="new"></div>&#39;);</td><td style="text-align:left;">所有匹配元素将会被当作是一个整体，在这个整体的外部用指定的 HTML 结构进行包裹。</td></tr><tr><td style="text-align:left;">.wrapInner()</td><td style="text-align:left;">$(&#39;.inner&#39;).wrapInner(&#39;<div class="new"></div>&#39;);</td><td style="text-align:left;">在匹配元素里的内容外包一层结构。用来包在匹配元素的内容外面的HTML片段，选择表达式，jQuery对象或者DOM元素</td></tr></tbody></table><h4 id="移除节点" tabindex="-1"><a class="header-anchor" href="#移除节点" aria-hidden="true">#</a> 移除节点</h4><table><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">用法</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">.remove()</td><td style="text-align:left;">$(&quot;.target&quot;).remove()</td><td style="text-align:left;">将匹配元素集合从DOM中删除。（注：同时移除元素上的事件及 jQuery 数据。）</td></tr><tr><td style="text-align:left;">.detach()</td><td style="text-align:left;">$(&quot;.target&quot;).detach()</td><td style="text-align:left;"><code>.detach()</code> 方法和<code>.remove()</code>一样, 除了 <code>.detach()</code>保存所有jQuery数据和被移走的元素相关联。当需要移走一个元素，不久又将该元素插入DOM时，这种方法很有用</td></tr><tr><td style="text-align:left;">.empty()</td><td style="text-align:left;">$(&#39;.target&#39;).empty()</td><td style="text-align:left;">从DOM中移除集合中匹配元素的所有子节点。这个方法不仅移除子元素（和其他后代元素），同样移除元素里的文本。因为，根据说明，元素里任何文本字符串都被看做是该元素的子节点</td></tr></tbody></table><h4 id="克隆节点" tabindex="-1"><a class="header-anchor" href="#克隆节点" aria-hidden="true">#</a> 克隆节点</h4><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>$(&#39;.target&#39;).clone(boolean)

一个布尔值，指示是否对事件处理程序和克隆的元素的所有子元素的数据应该被复制。默认false
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>深度复制所有匹配的元素集合，包括括所有匹配元素、匹配元素的下级元素、文字节点。出于性能方面的考虑，表单元素动态的状态（例如，用户将数据输入到<code>input</code>和 <code>textarea</code>，或者 用户在<code>select</code>中已经选中某一项）不会被复制到克隆元素。克隆操作将设置这些字段为HTML中指定的默认值。</p>`,127),i=[l];function d(p,o){return n(),a("div",null,i)}const u=t(e,[["render",d],["__file","JQuery.html.vue"]]);export{u as default};
